-- Create "finance_payments" table
CREATE TABLE "finance_payments" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "payment_no" character varying NOT NULL,
  "direction" character varying NOT NULL,
  "status" character varying NOT NULL DEFAULT 'DRAFT',
  "counterparty_type" character varying NOT NULL,
  "counterparty_id" bigint NOT NULL,
  "amount" numeric(20,6) NOT NULL,
  "currency" character varying NOT NULL,
  "account_ref" character varying NOT NULL,
  "evidence_ref" character varying NOT NULL,
  "idempotency_key" character varying NOT NULL,
  "idempotency_payload_hash" character varying NOT NULL,
  "version" bigint NOT NULL DEFAULT 1,
  "occurred_at" timestamptz NOT NULL,
  "posted_at" timestamptz NULL,
  "posted_by" bigint NULL,
  "reversed_at" timestamptz NULL,
  "reversed_by" bigint NULL,
  "reverse_reason" character varying NULL,
  "created_by" bigint NOT NULL,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  PRIMARY KEY ("id"),
  CONSTRAINT "finance_payments_amount_positive" CHECK (amount > (0)::numeric),
  CONSTRAINT "finance_payments_counterparty_allowed" CHECK ((counterparty_type)::text = ANY ((ARRAY['CUSTOMER'::character varying, 'SUPPLIER'::character varying])::text[])),
  CONSTRAINT "finance_payments_currency_allowed" CHECK ((currency)::text = ANY ((ARRAY['USD'::character varying, 'CNY'::character varying, 'HKD'::character varying])::text[])),
  CONSTRAINT "finance_payments_direction_allowed" CHECK ((direction)::text = ANY ((ARRAY['RECEIPT'::character varying, 'DISBURSEMENT'::character varying])::text[])),
  CONSTRAINT "finance_payments_intent_bundle" CHECK (((length(TRIM(BOTH FROM idempotency_key)) >= 1) AND (length(TRIM(BOTH FROM idempotency_key)) <= 128)) AND (length((idempotency_payload_hash)::text) = 64)),
  CONSTRAINT "finance_payments_status_allowed" CHECK ((status)::text = ANY ((ARRAY['DRAFT'::character varying, 'POSTED'::character varying, 'REVERSED'::character varying])::text[])),
  CONSTRAINT "finance_payments_version_positive" CHECK (version > 0)
);
-- Create index "financepayment_counterparty_type_counterparty_id_currency_statu" to table: "finance_payments"
CREATE INDEX "financepayment_counterparty_type_counterparty_id_currency_statu" ON "finance_payments" ("counterparty_type", "counterparty_id", "currency", "status");
-- Create index "financepayment_created_by_idempotency_key" to table: "finance_payments"
CREATE UNIQUE INDEX "financepayment_created_by_idempotency_key" ON "finance_payments" ("created_by", "idempotency_key");
-- Create index "financepayment_payment_no" to table: "finance_payments"
CREATE UNIQUE INDEX "financepayment_payment_no" ON "finance_payments" ("payment_no");
