-- Create "inventory_operations" table
CREATE TABLE "inventory_operations" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "operation_no" character varying NOT NULL,
  "operation_type" character varying NOT NULL,
  "status" character varying NOT NULL DEFAULT 'DRAFT',
  "reason" character varying NOT NULL,
  "approval_ref" character varying NULL,
  "idempotency_key" character varying NOT NULL,
  "idempotency_payload_hash" character varying NOT NULL,
  "idempotency_item_count" bigint NOT NULL,
  "version" bigint NOT NULL DEFAULT 1,
  "posted_at" timestamptz NULL,
  "posted_by" bigint NULL,
  "cancelled_at" timestamptz NULL,
  "cancelled_by" bigint NULL,
  "cancel_reason" character varying NULL,
  "created_by" bigint NOT NULL,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  PRIMARY KEY ("id"),
  CONSTRAINT "inventory_operations_cancel_bundle" CHECK ((((status)::text = 'CANCELLED'::text) AND (cancelled_at IS NOT NULL) AND (cancelled_by IS NOT NULL) AND (cancel_reason IS NOT NULL) AND (length(TRIM(BOTH FROM cancel_reason)) > 0)) OR (((status)::text <> 'CANCELLED'::text) AND (cancelled_at IS NULL) AND (cancelled_by IS NULL) AND (cancel_reason IS NULL))),
  CONSTRAINT "inventory_operations_intent_bundle" CHECK (((length(TRIM(BOTH FROM idempotency_key)) >= 1) AND (length(TRIM(BOTH FROM idempotency_key)) <= 128)) AND (length((idempotency_payload_hash)::text) = 64) AND (idempotency_item_count > 0)),
  CONSTRAINT "inventory_operations_status_allowed" CHECK ((status)::text = ANY ((ARRAY['DRAFT'::character varying, 'POSTED'::character varying, 'CANCELLED'::character varying])::text[])),
  CONSTRAINT "inventory_operations_type_allowed" CHECK ((operation_type)::text = ANY ((ARRAY['CYCLE_COUNT'::character varying, 'TRANSFER'::character varying, 'MANUAL_ADJUSTMENT'::character varying])::text[])),
  CONSTRAINT "inventory_operations_version_positive" CHECK (version > 0)
);
