-- Create index "salesreturn_created_by_idempotency_key" to table: "sales_returns"
CREATE UNIQUE INDEX "salesreturn_created_by_idempotency_key" ON "sales_returns" ("created_by", "idempotency_key");
-- Create index "salesreturn_return_no" to table: "sales_returns"
CREATE UNIQUE INDEX "salesreturn_return_no" ON "sales_returns" ("return_no");
-- Create index "salesreturn_shipment_id_status" to table: "sales_returns"
CREATE INDEX "salesreturn_shipment_id_status" ON "sales_returns" ("shipment_id", "status");
-- Create "sales_return_items" table
CREATE TABLE "sales_return_items" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "line_no" character varying NOT NULL,
  "shipment_item_id" bigint NOT NULL,
  "subject_type" character varying NOT NULL DEFAULT 'PRODUCT',
  "product_id" bigint NOT NULL,
  "product_sku_id" bigint NULL,
  "warehouse_id" bigint NOT NULL,
  "unit_id" bigint NOT NULL,
  "lot_id" bigint NULL,
  "quality_inspection_id" bigint NOT NULL,
  "quantity" numeric(20,6) NOT NULL,
  "condition" character varying NOT NULL DEFAULT 'PENDING_INSPECTION',
  "note" character varying NULL,
  "created_at" timestamptz NOT NULL,
  "sales_return_id" bigint NOT NULL,
  PRIMARY KEY ("id"),
  CONSTRAINT "sales_return_items_sales_returns_items" FOREIGN KEY ("sales_return_id") REFERENCES "sales_returns" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "sales_return_items_quantity_positive" CHECK (quantity > (0)::numeric),
  CONSTRAINT "sales_return_items_subject_allowed" CHECK ((subject_type)::text = 'PRODUCT'::text)
);
-- Create index "salesreturnitem_product_id_product_sku_id_warehouse_id_lot_id" to table: "sales_return_items"
CREATE INDEX "salesreturnitem_product_id_product_sku_id_warehouse_id_lot_id" ON "sales_return_items" ("product_id", "product_sku_id", "warehouse_id", "lot_id");
-- Create index "salesreturnitem_quality_inspection_id" to table: "sales_return_items"
CREATE UNIQUE INDEX "salesreturnitem_quality_inspection_id" ON "sales_return_items" ("quality_inspection_id");
-- Create index "salesreturnitem_sales_return_id_line_no" to table: "sales_return_items"
CREATE UNIQUE INDEX "salesreturnitem_sales_return_id_line_no" ON "sales_return_items" ("sales_return_id", "line_no");
-- Create index "salesreturnitem_shipment_item_id" to table: "sales_return_items"
CREATE INDEX "salesreturnitem_shipment_item_id" ON "sales_return_items" ("shipment_item_id");
